<template>
	<view>
		<u-popup v-model="popupShow" mode="center" :z-index="12" :custom-style="{}"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			@close="close">
			<view class="popup-box">
				<view class="popup-title">预警余额</view>
				<view class="popup-content">
					<u-form :model="form" ref="uForm" :label-width="140">
						<u-form-item label="金额" prop="warn">
							<u-input v-model.number="form.warn" />
						</u-form-item>
					</u-form>
				</view>
				<view class="popup-footer">
					<u-button type="warning" shape="circle" @click="handelOk">确 定</u-button>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {

		},
		data() {
			return {
				popupShow: false,

				form: {
					warn: 0
				},
			};
		},
		computed: {

		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			showEdit({
				warn
			}) {
				this.form.warn = warn
				this.popupShow = true
			},
			close() {
				this.form = this.$options.data().form
			},
			// 提交
			async handelOk() {
				await this.$u.api.setWarn(this.form)
				this.$emit('ok', this.form)
				this.popupShow = false
			},
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-box {
		width: 80vw;
	}

	.popup-title {
		height: 100rpx;
		line-height: 100rpx;
		text-align: center;
		font-weight: bold;
	}

	.popup-content {
		padding: 20rpx;

		.wrap {
			background-color: #f4f4f5;
			height: 300rpx;
			overflow-y: auto;
		}
	}

	.popup-footer {
		padding: 40rpx;
	}
</style>