<template>
	<view>
		<u-popup v-model="popupShow" mode="center" :z-index="zIndex" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="false"
			:duration="150" width="600" @close="close" @open="open">
			<view class="popup-box">
				<view class="popup-title">{{title}}</view>
				<view class="desc mt-20" v-if="desc">{{desc}}</view>
				<view class="btn-box">
					<view class="btn-item" @click="handelCancel">取消</view>
					<view class="btn-item confirm-item" @click="handelConfirm">{{confirmText}}</view>
				</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			},
			zIndex: {
				type: Number,
				default: 100
			},
			value: {
				type: Boolean,
				default: false
			},
			title: {
				type: String,
				default: ''
			},
			desc: {
				type: String,
				default: ''
			},
			confirmText: {
				type: String,
				default: '删除'
			},
		},
		data() {
			return {

			}
		},
		computed: {
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				}
			},
		},
		methods: {
			open() {

			},
			close() {},
			handelCancel() {
				this.popupShow = false
			},
			handelConfirm() {
				this.popupShow = false
				this.$emit('confirm')
			}
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-box {
		display: flex;
		align-items: center;
		justify-content: center;
		flex-direction: column;
		height: 100%;
		padding: 40rpx 0;

		.popup-title {
			display: flex;
			align-items: center;
			justify-content: center;
			font-weight: bold;
		}

		.desc {
			text-align: center;
			height: 60rpx;
			line-height: 60rpx;
		}

		.btn-box {
			display: flex;
			gap: 40rpx;
			padding: 0 60rpx;
			width: 100%;
			margin-top: 20rpx;

			.btn-item {
				flex: 1;
				height: 70rpx;
				border: 1px solid #eee;
				border-radius: 35rpx;
				display: flex;
				align-items: center;
				justify-content: center;
			}

			.confirm-item {
				background-color: #FD3750;
				color: #fff;
			}
		}
	}
</style>