<template>
	<view>
		<u-navbar back-text="订阅通知" :z-index="980" :custom-back="$util.back">
			<template #right>
				<view class="navbar-right">
					<view class="btn-item serch-btn btn bg-gray" @click="handelGoodsClick">
						<u-icon name="search"></u-icon>
						<text>调价通知商品</text>
					</view>
				</view>
			</template>
		</u-navbar>
		<scroll-view @touchmove.stop :scroll-y="true" class="scroll_content" :rebound="false"
			:style="{height:scrollHeight+'px'}">
			<view class="config-box">
				<view class="config-item" v-for="item,index in list" :key="index">
					<view class="top">
						<text class="name">{{item.title}}</text>
						<view class="set-btn" v-if="item.mark == 'user_send_supyue'">
							<view>预警设置：{{warn ? warn:''}}</view>
							<view class="btn bg-blue" v-if="warn > 0" @click="handelWarnClick">
								<u-icon name="setting"></u-icon>
								<text>设置</text>
							</view>
							<view class="btn bg-blue" v-else @click="handelWarnClick">
								<u-icon name="setting"></u-icon>
								<text>未设置</text>
							</view>
						</view>
					</view>
					<view class="bottom">
						<view class="switch-box">
							<view class="switch-item" v-if="is_open_system && item.is_system == 1">
								<text>站内信</text>
								<u-switch v-model="item.system_status" size="40" :active-value="1" :inactive-value="0"
									@change="updateField(item.id, 'is_system', $event)"></u-switch>
							</view>
							<view class="switch-item" v-if="is_open_wechat  && item.is_wechat == 1">
								<text>微信公众号</text>
								<u-switch v-model="item.wechat_status" size="40" :active-value="1" :inactive-value="0"
									@change="updateField(item.id, 'is_wechat', $event)">></u-switch>
							</view>
							<view class="switch-item" v-if="is_open_email && item.is_email == 1">
								<text>邮箱</text>
								<u-switch v-model="item.email_status" size="40" :active-value="1" :inactive-value="0"
									@change="updateField(item.id, 'is_email', $event)">></u-switch>
							</view>
						</view>
					</view>
				</view>
				<view class="config-item">
					<view class="top">
						<text class="name">通知接受人</text>
						<view class="set-btn">
							<view class="btn bg-blue" @click="onAddNoticeUser">
								<u-icon name="plus"></u-icon>
								<text>添加</text>
							</view>
						</view>
					</view>
					<view class="bottom">
						<view class="user-list">
							<view class="user-item" v-for="(item,index) in userGoodsPriceList" :key="index">
								<u-image class="img" :src="item.avatar" :width="50" :height="50"
									border-radius="50%"></u-image>
								<view class="name line1">{{item.nickname}}</view>
								<view class="del-btn" @click="onDelNoticeUser(item)"></view>
							</view>
						</view>
					</view>
				</view>
			</view>
		</scroll-view>
		<Warn ref="warn" @ok="handelWarnSet" />
		<wx-scan-qrcode ref='wx_scan_qrcode' />
		<confirm v-model="showConfirm" title="您确定要删除该用户吗?" @confirm="handelConfirm" />
	</view>
</template>

<script>
	import Warn from './components/warn'
	import WxScanQRCode from './components/WxScanQRCode'
	import Confirm from '@/components/confirm/common'

	export default {
		components: {
			Warn,
			'wx-scan-qrcode': WxScanQRCode,
			Confirm
		},
		data() {
			return {
				list: [],
				is_open_system: false, //是否显示站内信列
				is_open_email: false, //是否显示邮箱列
				is_open_wechat: false, //是否显示微信公众号列
				is_open_app: false,
				need_bind_wechat: false, //是否需要绑定微信公众号
				need_bind_email: false, //是否需要绑定微信
				user_goods_price: false, //是否开启了调价商品通知
				warn: 0,

				userGoodsPriceList: [],
				showConfirm: false,
				deleteUserId: null,
			};
		},
		computed: {
			scrollHeight() {
				return this.deviceInfo.screenHeight - 44
			}
		},
		onReady() {},
		onLoad() {
			this.fetchData()
		},
		methods: {
			async fetchData() {
				const {
					is_open_app,
					is_open_email,
					is_open_system,
					is_open_wechat,
					need_bind_email,
					need_bind_wechat,
					user_goods_price,
					warn,
					list,
					user_goods_price_list
				} = await this.$u.api.getNoticeSetting2()
				this.list = list
				this.is_open_app = is_open_app
				this.is_open_email = is_open_email
				this.is_open_system = is_open_system
				this.is_open_wechat = is_open_wechat
				this.need_bind_wechat = need_bind_wechat
				this.need_bind_email = need_bind_email
				this.user_goods_price = user_goods_price
				this.warn = warn || 0

				this.userGoodsPriceList = user_goods_price_list || []
			},
			async updateField(notice_id, field, status) {
				await this.$u.api.setNoticeSetting2({
					notice_id,
					field,
					status
				})
				this.$util.msg('修改成功')
			},
			// 设置点击
			handelWarnClick() {
				this.$refs['warn'].showEdit({
					warn: this.warn
				})
			},
			// 设置回调
			handelWarnSet({
				warn
			}) {
				this.warn = warn
			},
			// 调价通知商品点击
			handelGoodsClick() {
				this.$util.on('/pages/ucenter_sub/set_notice/notice_goods')
			},
			async onAddNoticeUser() {
				const {
					ticket
				} = await this.$u.api.getNoticeLoginUrl()
				let url = `https://mp.weixin.qq.com/cgi-bin/showqrcode?ticket=${ticket}`
				this.$refs['wx_scan_qrcode'].show({
					url
				})
			},
			onDelNoticeUser(row) {
				this.deleteUserId = row.id
				this.showConfirm = true
			},
			async handelConfirm() {
				await this.$u.api.delNoticeUser({
					id: this.deleteUserId
				})
				this.$util.msg('删除用户成功')
				this.fetchData()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.navbar-right {
		margin-right: 18rpx;
		display: flex;
		gap: 20rpx;

		.btn-item {
			white-space: nowrap;
		}

		.btn-item:active {
			opacity: .6;
		}
	}

	.config-box {
		display: flex;
		flex-direction: column;
		gap: 20rpx;
		padding: 20rpx;

		.config-item {
			position: relative;
			display: flex;
			flex-direction: column;
			gap: 20rpx;
			background-color: #fff;
			padding: 20rpx;
			cursor: pointer;
			border-radius: 20rpx;

			.top {
				display: flex;
				align-items: center;
				justify-content: space-between;
				border-bottom: 2rpx solid #e5e5e5;
				padding-bottom: 20rpx;

				.name {
					position: relative;
					font-weight: bold;
					padding-left: 20rpx;

					&::before {
						content: '';
						position: absolute;
						left: 0;
						top: 50%;
						transform: translateY(-50%);
						width: 6rpx;
						height: 26rpx;
						background-color: rgb(41, 121, 255);
					}
				}

				.set-btn {
					display: flex;
					gap: 10rpx;
				}
			}

			.bottom {
				.switch-box {
					display: flex;
					align-items: center;
					gap: 30rpx;

					.switch-item {
						display: flex;
						gap: 10rpx;
						white-space: nowrap;
					}
				}

				.user-list {
					display: grid;
					grid-template-columns: repeat(5, 1fr);
					gap: 20rpx;

					.user-item {
						display: flex;
						flex-direction: column;
						justify-content: center;
						align-items: center;
						position: relative;
						gap: 20rpx;
						border: 2rpx solid #e5e5e5;
						border-radius: 6rpx;
						padding: 10rpx;
						width: 100%;
						overflow: hidden;

						.name {
							width: 100%;
						}

						.del-btn {
							position: absolute;
							right: 0;
							top: 0;
							background-color: rgba(255, 0, 0, .7);
							border-bottom-left-radius: 100%;
							width: 30rpx;
							height: 30rpx;

							&:active {
								opacity: .4;
							}

							&:before {
								content: '×';
								position: absolute;
								top: 0rpx;
								right: 2rpx;
								color: white;
								font-size: 28rpx;
								font-weight: bold;
								line-height: 1;
							}
						}
					}
				}
			}
		}
	}
</style>